    from metamath_setmm_provider.shards.s000 import id, imim1, syl9r

    _step_1 = proof.use(
        imim1,
        subst={
            "ph": "wi(ph, ps)",
            "ps": "ch",
            "ch": "ph",
        },
    )  # ⊢ wi(wi(wi(ph, ps), ch), wi(wi(ch, ph), wi(wi(ph, ps), ph)))
    _step_2 = proof.use(
        id,
        subst={
            "ph": "wi(wi(wi(ph, ps), ph), ph)",
        },
    )  # ⊢ wi(wi(wi(wi(ph, ps), ph), ph), wi(wi(wi(ph, ps), ph), ph))
    _step_3 = proof.use(
        syl9r,
        _step_1,
        _step_2,
    )  # ⊢ wi(wi(wi(wi(ph, ps), ph), ph), wi(wi(wi(ph, ps), ch), wi(wi(ch, ph), ph)))
    return proof.qed(_step_3)


